create table dirkspzm32.lvs_serie_id_pos (
    sid                  varchar2(2 char) default '01' not null enable,
    firma_nr             number(2, 0) default 1 not null enable,
    serie_id             number(*, 0) not null enable,
    serie_pos_lfdn       number(*, 0) not null enable,
    serie_id_lfdn        number(*, 0) not null enable,
    serie_nr             varchar2(50 char) not null enable,
    lam_id               number(*, 0),
    serie_nr_extern      varchar2(50 char),
    created_date         date not null enable,
    created_login_id     number(*, 0) not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.lvs_serie_id_pos
    add constraint pk_serie_id_lfdn primary key ( serie_id_lfdn )
        using index enable;

alter table dirkspzm32.lvs_serie_id_pos add constraint uk_serie_nr unique ( serie_nr )
    using index enable;


